'use client';

import { m } from 'framer-motion';
import Box from '@mui/material/Box';
import Stack from '@mui/material/Stack';
import Typography from '@mui/material/Typography';
import { useTheme, styled, alpha } from '@mui/material/styles';

// ----------------------------------------------------------------------

const SwitchRoot = styled('div')(({ theme }) => ({
  height: 64,
  display: 'inline-flex',
  justifyContent: 'center',
  alignItems: 'center',
  gap: theme.spacing(2),
  padding: theme.spacing(0.75),
  overflow: 'hidden',
  backgroundColor: theme.palette.common.white,
  borderRadius: 40,
  border: `1.5px solid ${theme.palette.common.white}`,
  position: 'relative',
  cursor: 'pointer',
}));

const SwitchSlider = styled(m.div)(({ theme }) => ({
  position: 'absolute',
  width: 144, // Matches FRAME 0:1942 width w-36 (36 * 4 = 144px)
  height: 'calc(100% - 12px)',
  backgroundColor: theme.palette.common.white,
  borderRadius: 40,
  boxShadow: `0px 6px 6px 0px ${alpha(theme.palette.primary.main, 0.05)}, 
              0px 13px 8px 0px ${alpha(theme.palette.primary.main, 0.03)}, 
              0px 24px 10px 0px ${alpha(theme.palette.primary.main, 0.01)}`,
  border: `1px solid ${theme.palette.common.white}`,
}));

const SwitchItem = styled(Box, {
  shouldForwardProp: (prop) => prop !== 'active',
})<{ active: boolean }>(({ theme, active }) => ({
  width: 144,
  height: '100%',
  display: 'flex',
  justifyContent: 'center',
  alignItems: 'center',
  zIndex: 1,
  transition: theme.transitions.create(['color'], {
    duration: theme.transitions.duration.shorter,
  }),
  color: active ? theme.palette.text.primary : theme.palette.text.secondary,
}));

// ----------------------------------------------------------------------

interface Props {
  isYearly: boolean;
  onChange: (isYearly: boolean) => void;
  discountLabel?: string;
}

export default function PricingPlanSelector({
  isYearly,
  onChange,
  discountLabel = 'Save 30% with yearly',
}: Props) {
  const theme = useTheme();

  return (
    <Stack
      spacing={4}
      alignItems="center"
      data-test-id="pricingplanselector"
      sx={{ position: 'relative' }}
    >
      {/* Discount Badge */}
      <Box
        sx={{
          px: 2,
          py: 0.75,
          bgcolor: 'primary.main',
          borderRadius: 1,
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
        }}
      >
        <Typography
          variant="subtitle2"
          sx={{
            color: 'common.white',
            fontWeight: 600,
            letterSpacing: -0.32,
          }}
        >
          {discountLabel}
        </Typography>
      </Box>

      {/* Switch Container */}
      <Box sx={{ position: 'relative' }}>
        {/* Glow / Decorative Background */}
        <Box
          sx={{
            position: 'absolute',
            top: '50%',
            left: '50%',
            transform: 'translate(-50%, -50%)',
            width: 384, // w-96
            height: 320, // h-80
            zIndex: 0,
            opacity: 0.3,
            pointerEvents: 'none',
            filter: 'blur(100px)',
            background: 'linear-gradient(135deg, #7C42F0 0%, #7C42F0 100%)',
          }}
        />

        {/* Switch */}
        <SwitchRoot onClick={() => onChange(!isYearly)}>
          <SwitchSlider
            initial={false}
            animate={{ x: isYearly ? 144 + 6 : 0 }}
            transition={{ type: 'spring', stiffness: 300, damping: 30 }}
          />
          <SwitchItem active={!isYearly}>
            <Typography variant="h6" component="span" sx={{ fontWeight: 500 }}>
              Monthly
            </Typography>
          </SwitchItem>
          <SwitchItem active={isYearly}>
            <Typography variant="h6" component="span" sx={{ fontWeight: 500 }}>
              Yearly
            </Typography>
          </SwitchItem>
        </SwitchRoot>

        {/* Decorative Arrow */}
        <Box
          sx={{
            position: 'absolute',
            right: -60,
            bottom: -20,
            width: 75,
            height: 61,
            pointerEvents: 'none',
            display: { xs: 'none', sm: 'block' },
          }}
        >
          <svg
            width="75"
            height="61"
            viewBox="0 0 75 61"
            fill="none"
            xmlns="http://www.w3.org/2000/svg"
          >
            <path
              d="M0.99997 16.2766C12.1409 6.60712 34.2895 -1.89341 52.6444 1.9412C64.6633 4.45214 72.3721 12.8059 73.3649 22.1616C74.6452 34.2118 67.5907 42.9196 58.2969 49.1941C54.8942 51.4913 49.6006 54.7519 49.4962 53.9788C49.0377 50.5835 54.0343 44.1388 56.4493 41.6757C58.6493 39.4319 53.5857 46.6769 52.6226 47.7612C51.9111 48.5623 46.2724 53.6282 48.1573 53.9393C54.5506 54.9946 59.0467 55.9842 64.7617 59.0245"
              stroke={theme.palette.primary.main}
              strokeWidth="2"
              strokeLinecap="round"
            />
          </svg>
        </Box>
      </Box>
    </Stack>
  );
}

