'use client';

import type { PlanKey } from '@/consts/plans';
import type { PlanType } from 'glitter-shared/consts/plan-types';

import { toast } from 'sonner';
import { log } from '@/utils/logger';
import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { setCookie } from '@/utils/cookies';
import axios from '@/utils/configured-axios';
import { COOKIE_NAMES } from '@/consts/cookies';
import { analytics } from '@/utils/segment/client';
import { APP_PATHS, AUTH_PATHS } from '@/routes/paths';
import { useUserContext } from '@/auth/hooks/use-user-context';
import { getPlanType } from 'glitter-shared/utils/get-plan-type';
import { Spacer } from '@/components/marketing-components/spacer';
import LoadingScreen from '@/components/loading-screen/LoadingScreen';
import { useConfirm } from '@/components/confirm-dialog/ConfirmDialogProvider';
import { CustomBreadcrumbs } from '@/components/custom-breadcrumbs/custom-breadcrumbs';
import { PageContainer } from '@/components/marketing-components/containers/page-container';
import { SectionContainer } from '@/components/marketing-components/containers/section-container';
import { SectionHeader } from '@/components/marketing-components/section-components/section-header';
import { PLAN_KEYS, FREQUENCIES, PLAN_TYPE_LIST, getPriceByPlanKeyAndFrequency } from '@/consts/plans';

import Box from '@mui/material/Box';
import Stack from '@mui/material/Stack';
import Alert from '@mui/material/Alert';
import Button from '@mui/material/Button';
import Typography from '@mui/material/Typography';

import PricingCard from '../components/pricing-card';
import EnterpriseSection from '../components/enterprise-section';
import PricingPlanSelector from '../components/pricing-plan-selector';
import FeaturesComparisonTable from '../components/features-comparison-table';
import { pricingCardData, YEARLY_DISCOUNT_PERCENT } from '../components/pricing-card-data';

declare global {
  const rewardful: any;
  const Rewardful: any;
}

export type DisplayCard = {
  planKey: PlanKey;
  name: PlanType['name'];
  displayName: string;
  caption: string;
  lists: string[];
  order: number;
  buttonLabel: string;
  disableButton: boolean;
  isDowngrade: boolean;
  isUpgrade: boolean;
  pricePerMember: number;
  minimumMembers: number;
  isCurrent: boolean;
  buttonColor: 'inherit' | 'primary' | 'secondary' | 'success' | 'error' | 'info' | 'warning';
  isGrey: boolean;
  isBlack: boolean;
  buttonVariant: 'contained' | 'outlined';
};

export function PricingView() {
  const [isYearly, setIsYearly] = useState(true);
  const { user, isUserLoading, isUserAuthenticated } = useUserContext();
  const [redirectingButton, setRedirectingButton] = useState<PlanKey | null>(null);
  const { push } = useRouter();
  const confirm = useConfirm();
  const [referral, setReferral] = useState(null);

  useEffect(() => {
    const checkRewardful = () => {
      if (typeof rewardful !== 'undefined') {
        rewardful('ready', () => {
          setReferral(Rewardful.referral);
        });
        return true;
      }
      return false;
    };

    // Try immediately first
    if (checkRewardful()) {
      return;
    }

    // If not available, poll until it loads
    const interval = setInterval(() => {
      if (checkRewardful()) {
        clearInterval(interval);
      }
    }, 100);

    // Cleanup on unmount
    return () => clearInterval(interval);
  }, []);

  if (isUserLoading) {
    return <LoadingScreen />;
  }

  // For signed-in users, extract their data
  const currentSubscriptionPlanKey =
    isUserAuthenticated && user ? (user.teams.current.subscription.plan as PlanKey) : null;
  const planType = getPlanType(currentSubscriptionPlanKey);
  const hasBillingAccess = isUserAuthenticated && user ? user.teams.current.permissions.hasBillingAccess : false;
  const currentlySubscribed = planType.name !== PLAN_TYPE_LIST.FREE;
  const forbidden = currentlySubscribed && !hasBillingAccess;
  const shouldOfferTrial = !isUserAuthenticated || (user?.teams.current.permissions.isEligibleForTrial ?? false);
  const isEnterprise = planType.name === PLAN_TYPE_LIST.ENTERPRISE;

  const pricingCards = pricingCardData.map((data) => {
    const planType = getPlanType(data.planKey);
    const price = getPriceByPlanKeyAndFrequency(data.planKey, isYearly ? FREQUENCIES.YEARLY : FREQUENCIES.MONTHLY);

    // Calculate price per member per month
    let pricePerMember = 0;
    if (price) {
      pricePerMember = price.costPerAdditionalMember || 0;
      if (isYearly) {
        // Convert yearly price to monthly for display
        pricePerMember = Math.round((pricePerMember / 12) * 100) / 100;
      }
    }

    const card: DisplayCard = {
      planKey: data.planKey,
      name: planType.name,
      displayName: planType.displayName,
      caption: data.caption,
      lists: data.lists,
      order: data.order,
      buttonLabel: '',
      disableButton: false,
      isDowngrade: false,
      isUpgrade: false,
      pricePerMember,
      minimumMembers: price?.minimumMembers || 1,
      isCurrent: false,
      buttonColor: 'inherit',
      isGrey: false,
      isBlack: false,
      buttonVariant: 'contained',
    };

    if (isEnterprise) {
      // For enterprise users, show static pricing page with no upgrade/downgrade options
      if (card.planKey === currentSubscriptionPlanKey) {
        card.buttonLabel = 'Current Plan';
      } else {
        card.buttonLabel = `Choose ${planType.displayName}`;
      }
      card.disableButton = true;
    } else if (!currentlySubscribed) {
      if (planType.name === PLAN_TYPE_LIST.FREE) {
        card.buttonLabel = `Current Plan`;
      } else if (shouldOfferTrial) {
        card.buttonLabel = `Start 7-Day Trial`;
      } else {
        card.buttonLabel = `Choose ${planType.displayName}`;
      }
    } else {
      const currentSubscriptionOrder = pricingCardData.find(
        (card) => card.planKey === currentSubscriptionPlanKey
      )?.order;
      const thisPlansOrder = card.order;

      if (currentSubscriptionOrder !== undefined && currentSubscriptionOrder > thisPlansOrder) {
        card.buttonLabel = `Downgrade to ${planType.displayName}`;
        card.isDowngrade = true;
      } else if (currentSubscriptionOrder !== undefined && currentSubscriptionOrder < thisPlansOrder) {
        card.buttonLabel = `Upgrade to ${planType.displayName}`;
        card.isUpgrade = true;
      } else {
        card.buttonLabel = 'Current Plan';
      }
    }

    card.isCurrent = card.planKey === currentSubscriptionPlanKey;
    card.disableButton = forbidden || card.isCurrent || isEnterprise;

    if (planType.name === PLAN_TYPE_LIST.FREE) {
      card.buttonColor = 'inherit';
      if (!card.isDowngrade) {
        card.isGrey = true;
      }
    } else if (planType.name === PLAN_TYPE_LIST.PRO) {
      card.buttonColor = 'primary';
    } else if (planType.name === PLAN_TYPE_LIST.TEAM) {
      if (currentSubscriptionPlanKey === PLAN_KEYS['pro-v1']) {
        card.buttonColor = 'primary';
      } else {
        card.buttonColor = 'inherit';
        card.isBlack = true;
      }
    }

    if (card.isDowngrade && !forbidden) {
      card.buttonVariant = 'outlined';
      card.buttonColor = 'inherit';
    } else {
      card.buttonVariant = 'contained';
    }

    card.lists = card.lists.map((list) => list.replace('{{{pricePerMember}}}', card.pricePerMember.toString()));

    return card;
  });

  const handleOpenPortal = async (planKey: PlanKey) => {
    try {
      setRedirectingButton(planKey);
      const response = await axios.post('/api/billing/generate-portal-url', { returnTo: 'pricing' });
      const { portalUrl } = response.data;
      window.location.href = portalUrl;
    } catch (error) {
      log.error(`Error generating portal URL`, error);
      toast.error('Error with billing portal. If this issue persists, please contact support.');
      setRedirectingButton(null);
    }
  };

  const handleSubscribe = async (planKey: PlanKey) => {
    // create checkout session
    try {
      setRedirectingButton(planKey);
      const response = await axios.post('/api/billing/create-checkout-session', {
        planKey,
        isYearly,
        returnTo: 'pricing',
        referral,
      });
      const { checkoutSessionUrl } = response.data;
      window.location.href = checkoutSessionUrl;
    } catch (error) {
      log.error(`Error generating checkout session URL`, error);
      toast.error('Error with billing portal. If this issue persists, please contact support.');
      setRedirectingButton(null);
    }
  };

  const handleClick = (card: DisplayCard) => {
    if (isUserAuthenticated && user && hasBillingAccess) {
      if (isEnterprise) {
        toast.info('Please contact your account manager for any plan changes.');
        return;
      }

      if (card.isUpgrade) {
        analytics.track('Upgrade Plan Clicked', { plan: card.planKey, buttonLabel: card.buttonLabel });
        handleUpgrade(card);
      } else if (card.isDowngrade) {
        analytics.track('Downgrade Plan Clicked', { plan: card.planKey, buttonLabel: card.buttonLabel });
        handleDowngrade(card);
      } else {
        analytics.track('Choose Plan Clicked', { plan: card.planKey, buttonLabel: card.buttonLabel });
        toast.info('Just a moment...');

        if (currentlySubscribed) {
          handleOpenPortal(card.planKey);
        } else {
          handleSubscribe(card.planKey);
        }
      }
    } else if (isUserAuthenticated && user && !hasBillingAccess) {
      toast.warning(
        <Stack direction="row" alignItems="center" spacing={1.3} sx={{ p: 1 }}>
          <Typography variant="body2">
            Please ask your team admin to make billing changes, or to make you an admin
          </Typography>
          <Button
            variant="contained"
            sx={{ flexShrink: 0 }}
            onClick={() => {
              toast.dismiss();
              push(APP_PATHS.team.root);
            }}
          >
            View Team
          </Button>
        </Stack>,
        {
          duration: 5000,
        }
      );
    } else {
      setCookie(COOKIE_NAMES.REQUESTED_PLAN_AFTER_SIGNGUP, card.planKey);
      push(AUTH_PATHS.signup);
    }
  };

  const handleUpgrade = async (card: DisplayCard) => {
    const planType = getPlanType(card.planKey);
    try {
      let content = `This will upgrade your subscription to the ${planType.displayName} plan`;
      content += isYearly
        ? `, billed annually.`
        : `.<br><br>You will be billed monthly (unless your current subscription is annual).`;
      confirm({
        title: `Upgrade to ${planType.displayName}?`,
        content,
        confirmText: 'Upgrade',
        onConfirm: async () => {
          // sends an api reques to /api/billing/update-subscription
          toast.info('Upgrading your subscription...');
          setRedirectingButton(card.planKey);
          await axios.post('/api/billing/update-subscription', {
            targetPlanKey: card.planKey,
            frequency: isYearly ? FREQUENCIES.YEARLY : FREQUENCIES.MONTHLY,
          });
          toast.success('Subscription upgraded successfully!');
          push(APP_PATHS.account.billing.root);
        },
      });
    } catch (error) {
      log.error(`Error upgrading subscription`, error);
      toast.error('Error upgrading subscription. If this issue persists, please contact support.');
      setRedirectingButton(null);
    }
  };

  const handleDowngrade = async (card: DisplayCard) => {
    const planType = getPlanType(card.planKey);
    try {
      let content;
      if (planType.name === PLAN_TYPE_LIST.FREE) {
        content = `This will downgrade your subscription to the ${planType.displayName} plan at the end of your subscription period. You will still have access to your current plan until then.<br><br>Are you sure you want to proceed?`;
      } else {
        content = `This will downgrade your subscription to the ${planType.displayName} plan. Are you sure you want to do this?`;
      }
      confirm({
        title: `Downgrade to ${planType.displayName}?`,
        content,
        confirmText: 'Downgrade',
        confirmButtonColor: 'error',
        onConfirm: async () => {
          // sends an api reques to /api/billing/update-subscription
          toast.info('Downgrading your subscription...');
          setRedirectingButton(card.planKey);
          await axios.post('/api/billing/update-subscription', {
            targetPlanKey: card.planKey,
            frequency: isYearly ? FREQUENCIES.YEARLY : FREQUENCIES.MONTHLY,
          });
          if (planType.name === PLAN_TYPE_LIST.FREE) {
            toast.info(
              `Downgrade complete. You still have access to your current plan until the end of the billing period`
            );
          } else {
            toast.info(`Downgrade complete.`);
          }
          push(APP_PATHS.account.billing.root);
        },
      });
    } catch (error) {
      log.error(`Error downgrading subscription`, error);
      toast.error('Error downgrading subscription. If this issue persists, please contact support.');
      setRedirectingButton(null);
    }
  };

  return (
    <PageContainer>
      <SectionContainer>
        <Box sx={{ display: 'flex', justifyContent: 'center', mb: 3 }}>
          <CustomBreadcrumbs links={[{ name: 'Home', href: '/' }, { name: 'Pricing' }]} />
        </Box>
        <SectionHeader
          title="Choose the plan that works for you"
          subtitle="All plans support desktop capture and AI speech to text"
          titleComponent="h1"
        />
        {isEnterprise && (
          <Alert
            severity="info"
            sx={{
              mt: { xs: 2, md: 4 },
              mb: { xs: 2, md: 3 },
              mx: { xs: 2, md: 5 },
              px: { xs: 2, md: 4 },
              py: { xs: 1.5, md: 2 },
            }}
          >
            You are currently on the Enterprise plan. Please contact your account manager for any plan changes.
          </Alert>
        )}

        <PricingPlanSelector
          frequency={isYearly ? FREQUENCIES.YEARLY : FREQUENCIES.MONTHLY}
          onFrequencyChange={(freq) => setIsYearly(freq === FREQUENCIES.YEARLY)}
          discountLabel={`save ${YEARLY_DISCOUNT_PERCENT}%`}
        />

        <Box
          gap={{ xs: 3, md: 0 }}
          display="grid"
          gridTemplateColumns={{ md: 'repeat(3, 1fr)' }}
          sx={{
            '@media print': {
              display: 'flex',
              flexDirection: 'column',
              gap: 2,
            },
          }}
        >
          {pricingCards.slice(0, 3).map((card, index) => (
            <PricingCard
              key={index}
              isYearly={isYearly}
              forbidden={forbidden}
              onClick={() => handleClick(card)}
              isLoading={redirectingButton === card.planKey}
              shouldOfferTrial={shouldOfferTrial}
              card={card}
            />
          ))}
        </Box>

        {pricingCards[3] && <EnterpriseSection isLoading={redirectingButton === pricingCards[3].planKey} />}

        <FeaturesComparisonTable />
      </SectionContainer>
      <Spacer />
    </PageContainer>
  );
}
